class Solution {
public:
    int leastOpsExpressTarget(int x, int target) {
        if (x == target) return 0;
        if (x > target) return 1;

        int res = INT_MAX;
        long long a = 1;
        for (int i = 30; i >= 0; --i) {
            if ((target - a) % x == 0) {
                res = min(res, i + (target - a) / x);
            }
            a *= x;
        }

        return res + 1;
    }
};
```
